contracts/Functions.sol.content:
// SPDX-License-Identifier: GPL-3.0

pragma solidity >=0.8.2 <0.9.0;

/**
 * @title Storage
 * @dev Store & retrieve value in a variable
 * @custom:dev-run-script ./scripts/deploy_with_ethers.ts
 */
contract Functions {
    uint8[4] public sarr = [1, 2, 3, 4];

    function f9() public {
        sarr[0] = 10;
    }

    function f10(uint8[4] memory arr) public returns (uint8){
        sarr[1] = 20;
        return arr[1];
    }
    function f11(uint8[4] storage arr) private {
        arr[2]=30;

    }
}

